#!/usr/bin/env bash
# Self-contained, agent-agnostic go-public installer.
# Generated by scripts/build-installer.sh — regenerate instead of editing by hand.
#
# Usage (from repo root):
#   bash setup-go-public-skill.sh
#   git add -A && git commit -m "Add go-public tooling"
#
# Writes the agent guides + CLI toolchain only. No git, remote, or network operations.
set -euo pipefail

TARGET_ROOT="${1:-.}"
TARGET_ROOT="$(cd "$TARGET_ROOT" && pwd)"

b64_decode() {
  if echo "dGVzdA==" | base64 -d >/dev/null 2>&1; then
    base64 -d
  else
    base64 -D
  fi
}

write_b64() {
  local rel="$1"
  local dest="$TARGET_ROOT/$rel"
  mkdir -p "$(dirname "$dest")"
  b64_decode >"$dest"
}

write_b64 'AGENTS.md' <<'__B64_AGENTS_md'

__B64_AGENTS_md

write_b64 'CLAUDE.md' <<'__B64_CLAUDE_md'

__B64_CLAUDE_md

write_b64 '.claude/skills/go-public/SKILL.md' <<'__B64__claude_skills_go-public_SKILL_md'

__B64__claude_skills_go-public_SKILL_md

write_b64 '.cursor/rules/go-public.mdc' <<'__B64__cursor_rules_go-public_mdc'

__B64__cursor_rules_go-public_mdc

write_b64 'scripts/go-public' <<'__B64_scripts_go-public'

__B64_scripts_go-public

write_b64 'scripts/go-public-lib/common.sh' <<'__B64_scripts_go-public-lib_common_sh'

__B64_scripts_go-public-lib_common_sh

write_b64 'scripts/go-public-lib/git.sh' <<'__B64_scripts_go-public-lib_git_sh'

__B64_scripts_go-public-lib_git_sh

write_b64 'scripts/go-public-lib/report.sh' <<'__B64_scripts_go-public-lib_report_sh'

__B64_scripts_go-public-lib_report_sh

write_b64 'scripts/go-public-lib/audit.sh' <<'__B64_scripts_go-public-lib_audit_sh'

__B64_scripts_go-public-lib_audit_sh

write_b64 'scripts/go-public-lib/docs.sh' <<'__B64_scripts_go-public-lib_docs_sh'

__B64_scripts_go-public-lib_docs_sh

write_b64 'scripts/go-public-lib/history.sh' <<'__B64_scripts_go-public-lib_history_sh'

__B64_scripts_go-public-lib_history_sh

write_b64 'scripts/go-public-lib/verify_clone.sh' <<'__B64_scripts_go-public-lib_verify_clone_sh'

__B64_scripts_go-public-lib_verify_clone_sh

write_b64 'adapters/generic.sh' <<'__B64_adapters_generic_sh'

__B64_adapters_generic_sh

write_b64 'adapters/go.sh' <<'__B64_adapters_go_sh'

__B64_adapters_go_sh

write_b64 'adapters/node.sh' <<'__B64_adapters_node_sh'

__B64_adapters_node_sh

write_b64 'adapters/python.sh' <<'__B64_adapters_python_sh'

__B64_adapters_python_sh

write_b64 'adapters/rust.sh' <<'__B64_adapters_rust_sh'

__B64_adapters_rust_sh

write_b64 '.go-public.yaml' <<'__B64__go-public_yaml'

__B64__go-public_yaml

write_b64 '.gitleaks.toml' <<'__B64__gitleaks_toml'

__B64__gitleaks_toml

write_b64 'LICENSE' <<'__B64_LICENSE'

__B64_LICENSE

write_b64 'README.md' <<'__B64_README_md'

__B64_README_md

chmod +x "$TARGET_ROOT/scripts/go-public"

echo "go-public installed under $TARGET_ROOT"
echo "  Agent guide:  AGENTS.md (read natively by Codex, Cursor, Factory Droid, Grok build)"
echo "  Claude Code:  CLAUDE.md + .claude/skills/go-public/SKILL.md"
echo "  Cursor:       .cursor/rules/go-public.mdc"
echo "  CLI:          scripts/go-public audit --dry-run"
